sql:
SELECT MAX(stillbirth_rate) AS max_stillbirth_rate
FROM stillbirths
WHERE organisation_unit_id = 0;

SELECT organisation_unit_name
FROM organisation_units
WHERE organisation_unit_id = 1;

SELECT MAX(access_count) AS max_daily_access
FROM (
  SELECT COUNT(*) AS access_count
  FROM access_logs
  GROUP BY access_date
) AS daily_access_counts;

SELECT record_id
FROM maternal_mortality
WHERE maternal_deaths > 50;

SELECT organisation_unit_id, organisation_unit_name, contact_person, contact_email
FROM organisation_units
WHERE description LIKE '%healthcare facility%';

SELECT AVG(value) AS average_value
FROM healthcare_facility_performance
WHERE performance_metric = 'Institutional Delivery Coverage';

SELECT neonatal_deaths
FROM neonatal_mortality
WHERE organisation_unit_id = 0 AND period_id = 1;

SELECT neonatal_deaths, neonatal_mortality_rate
FROM neonatal_mortality
WHERE record_id = 0 AND period_id = 1;

SELECT AVG(value) AS average_institutional_delivery_coverage
FROM healthcare_facility_performance
WHERE performance_metric = 'Institutional Delivery Coverage';

SELECT COUNT(*) 
   FROM organisation_units 
   WHERE description LIKE '%region%';

SELECT performance_metric, AVG(value) as average_performance
FROM healthcare_facility_performance
GROUP BY performance_metric;

SELECT period_id, SUM(maternal_deaths) AS total_maternal_deaths
FROM maternal_mortality
GROUP BY period_id;

external_knowledge:
- Institutional delivery coverage refers to the percentage of deliveries that take place in a healthcare facility; 
- Maternal mortality ratio is the number of maternal deaths per 100,000 live births; 
- Neonatal mortality rate is the number of deaths per 1,000 live births that occur during the first 28 days of life.

